import { GoogleGenAI, Type } from "@google/genai";
import { DrugInfo } from "../types";

// Initialize the client.
// Note: The API key is injected via vite.config.ts definition of process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Schema for structured output
const drugInfoSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "药品的通用名称和商品名称" },
    indications: { type: Type.STRING, description: "适应症，治什么病" },
    dosage: { type: Type.STRING, description: "具体的用法用量，成人儿童区别" },
    contraindications: { type: Type.STRING, description: "禁忌症，哪些人不能吃" },
    storage: { type: Type.STRING, description: "贮藏条件" },
    sideEffects: { type: Type.STRING, description: "常见的不良反应" },
    summary: { type: Type.STRING, description: "一段通俗易懂的口语化总结，用于语音播报，字数控制在150字以内，语气亲切。" },
  },
  required: ["name", "indications", "dosage", "contraindications", "summary"],
};

/**
 * 提取 Base64 字符串中的实际数据部分，移除前缀 (data:image/jpeg;base64,...)
 */
function cleanBase64(base64: string): string {
  return base64.split(',')[1] || base64;
}

/**
 * 通过文本查询药品信息
 */
export const getDrugInfoFromText = async (query: string): Promise<DrugInfo> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Flash model is good for general text too
      contents: `请查询药品 "${query}" 的详细说明书信息。如果找不到该药品，请在 name 字段返回"未找到药品"，并在 summary 中说明。`,
      config: {
        responseMimeType: "application/json",
        responseSchema: drugInfoSchema,
        systemInstruction: "你是一位专业的药师助手。请根据用户提供的药品名称，查询准确的药品说明书信息。所有输出必须是简体中文。",
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as DrugInfo;
  } catch (error) {
    console.error("Gemini Text Search Error:", error);
    throw new Error("查询失败，请检查网络或重试");
  }
};

/**
 * 通过图片识别药品信息
 */
export const getDrugInfoFromImage = async (base64Image: string): Promise<DrugInfo> => {
  try {
    const imagePart = {
      inlineData: {
        mimeType: 'image/jpeg', // Assume JPEG from camera/upload
        data: cleanBase64(base64Image),
      },
    };

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          imagePart,
          { text: "请识别这张图片中的药品。提取完整的药品说明书信息。如果图片不清或不是药品，请在 name 字段返回错误提示。" }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: drugInfoSchema,
        systemInstruction: "你是一位专业的药师助手。请分析上传的药品包装或说明书图片，提取关键信息。如果图片模糊，尽最大努力识别。",
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as DrugInfo;
  } catch (error) {
    console.error("Gemini Image Analysis Error:", error);
    throw new Error("图片识别失败，请确保图片清晰");
  }
};

