const DEFAULT_RESULT: DrugInfo = MOCK_DATABASE["阿莫西林"];
const DRUG_KEYS = Object.keys(MOCK_DATABASE);

/**
 * 模拟延时函数
 */
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * 模拟通过文本查询
 */
export const getDrugInfoFromText = async (query: string): Promise<DrugInfo> => {
  await delay(600); // 模拟网络请求时间

  const cleanQuery = query.trim();

  // 1. 精确匹配
  if (MOCK_DATABASE[cleanQuery]) {
    return MOCK_DATABASE[cleanQuery];
  }

  // 2. 模糊匹配 (查找 query 是否包含 key，或 key 是否包含 query)
  // 例如：输入"999" -> 匹配 "感冒灵" (假设key只有感冒灵) - 这里的key是 "感冒灵"
  // 改进：遍历数据库所有 Key
  const foundKey = DRUG_KEYS.find(key => 
    key.includes(cleanQuery) || cleanQuery.includes(key) || MOCK_DATABASE[key].name.includes(cleanQuery)
  );

  if (foundKey) {
    return MOCK_DATABASE[foundKey];
  }

  // 如果没找到，为了演示效果，返回默认数据
  return {
    ...DEFAULT_RESULT,
    name: `未找到 "${cleanQuery}" (演示数据库)`,
    summary: `抱歉，演示数据库中没有找到 "${cleanQuery}"。您可以尝试搜索：阿莫西林、布洛芬、头孢、感冒灵、健胃消食片等。`
  };
};

/**
 * 模拟通过图片识别
 * 
 * 策略：为了让演示更加生动，模拟 AI "识别" 的过程。
 * 既然无法真的分析图片，我们随机返回数据库中的一种药品，
 * 这样用户多次点击扫描可以看到不同的结果，展示数据库的丰富性。
 */
export const getDrugInfoFromImage = async (base64Image: string): Promise<DrugInfo> => {
  await delay(1500); // 模拟 AI 分析图片的耗时

  // 随机选择一个药品
  const randomKey = DRUG_KEYS[Math.floor(Math.random() * DRUG_KEYS.length)];
  const result = MOCK_DATABASE[randomKey];

  // 返回结果 (稍微修改一下name，让用户知道是识别结果)
  return {
    ...result,
    // 我们不修改原始 name，保持专业性，但在 ResultCard 界面会显示 "智能识别结果"
  };
};

