export const ResultCard: React.FC<ResultCardProps> = ({ info, onBack }) => {
  const [isPlaying, setIsPlaying] = useState(false);

  // Stop audio when component unmounts
  useEffect(() => {
    return () => {
      window.speechSynthesis.cancel();
    };
  }, []);

  const handlePlayAudio = () => {
    if (isPlaying) {
      window.speechSynthesis.cancel();
      setIsPlaying(false);
      return;
    }

    const utterance = new SpeechSynthesisUtterance(info.summary);
    utterance.lang = 'zh-CN'; // 设置为中文
    utterance.rate = 1.0; // 语速
    utterance.pitch = 1.0; // 音调

    utterance.onend = () => {
      setIsPlaying(false);
    };

    utterance.onerror = (e) => {
      console.error("Speech synthesis error:", e);
      setIsPlaying(false);
    };

    setIsPlaying(true);
    window.speechSynthesis.speak(utterance);
  };

  return (
    <div className="w-full max-w-md mx-auto bg-white rounded-3xl shadow-xl overflow-hidden flex flex-col h-[85vh]">
      {/* Header Image/Banner */}
